function groupedSignals(filter='all'){const groups=new Map();signals.forEach(signal=>{if(!groups.has(signal.name))groups.set(signal.name,[]);groups.get(signal.name).push(signal)});return[...groups.entries()].map(([name,items])=>{const type=items.some(item=>item.type==='urgent')?'urgent':'watch';const student=classSettings.students.find(row=>row.name===name);const hasPrevious=student&&latestByStudent(allResponses,previousMonth(selectedAnalysisMonth)).has(Number(student.number));const changed=items.some(item=>item.evidence.some(evidence=>String(evidence).includes('→')));const trend=!hasPrevious?'전월 비교 자료 없음':changed?'전월 대비 변화 확인':'이번 달 확인 신호';const protectiveFactors=[...new Set(items.flatMap(item=>item.protectiveFactors||[]))];return{name,items,type,tag:signalTag(type),ids:items.map(item=>item.id),trend,protectiveFactors}}).filter(group=>filter==='all'||group.type===filter).sort((a,b)=>({urgent:0,watch:1}[a.type]-{urgent:0,watch:1}[b.type]))}
function buildRelationshipAnalysis(responses,month){const current=latestByStudent(responses,month);const total=classSettings.students.length;const submitted=current.size;const relationResponders=[...current.entries()].filter(([,item])=>(payloadOf(item).relationships||[]).length);const ready=total>0&&submitted/total>=.8&&relationResponders.length/total>=.8;const scores=new Map();relationResponders.forEach(([rater,item])=>(payloadOf(item).relationships||[]).forEach(row=>scores.set(`${rater}:${Number(row.targetNumber)}`,Number(row.score))));const students=classSettings.students.filter(student=>current.has(Number(student.number))||[...scores.keys()].some(key=>Number(key.split(':')[1])===Number(student.number)));const mutual=[];students.forEach((student,index)=>students.slice(index+1).forEach(other=>{const a=Number(student.number),b=Number(other.number),ab=scores.get(`${a}:${b}`),ba=scores.get(`${b}:${a}`);if(ab>=4&&ba>=4)mutual.push({a,b,strength:Math.min(ab,ba)})}));const adjacency=new Map(students.map(student=>[Number(student.number),new Set()]));mutual.filter(edge=>edge.strength===5).forEach(edge=>{adjacency.get(edge.a)?.add(edge.b);adjacency.get(edge.b)?.add(edge.a)});const visited=new Set();const groups=[];students.forEach(student=>{const start=Number(student.number);if(visited.has(start))return;const stack=[start],component=[];visited.add(start);while(stack.length){const value=stack.pop();component.push(value);(adjacency.get(value)||[]).forEach(next=>{if(!visited.has(next)){visited.add(next);stack.push(next)}})}if(component.length>=2)groups.push(component)});const groupByStudent=new Map();groups.forEach((group,index)=>group.forEach(number=>groupByStudent.set(number,index)));const connectors=students.map(student=>{const number=Number(student.number);const touched=new Set();mutual.filter(edge=>edge.a===number||edge.b===number).forEach(edge=>{const other=edge.a===number?edge.b:edge.a;const group=groupByStudent.get(other);if(group!==undefined)touched.add(group)});return{number,name:student.name,groups:[...touched],connections:mutual.filter(edge=>edge.a===number||edge.b===number).length}}).filter(item=>item.groups.length>=2);const peripheral=students.map(student=>{const number=Number(student.number);return{number,name:student.name,connections:mutual.filter(edge=>edge.a===number||edge.b===number).length,group:groupByStudent.get(number)}}).filter(item=>item.connections<=1&&item.group===undefined);const groupMetrics=[];for(let i=0;i<groups.length;i++)for(let j=i+1;j<groups.length;j++){const between=[];groups[i].forEach(a=>groups[j].forEach(b=>{const ab=scores.get(`${a}:${b}`),ba=scores.get(`${b}:${a}`);if(ab)between.push(ab);if(ba)between.push(ba)}));const internal=[];[groups[i],groups[j]].forEach(group=>group.forEach((a,index)=>group.slice(index+1).forEach(b=>{const ab=scores.get(`${a}:${b}`),ba=scores.get(`${b}:${a}`);if(ab)internal.push(ab);if(ba)internal.push(ba)})));if(between.length&&internal.length){const betweenAvg=between.reduce((sum,value)=>sum+value,0)/between.length;const internalAvg=internal.reduce((sum,value)=>sum+value,0)/internal.length;if(internalAvg-betweenAvg>=1.2)groupMetrics.push({a:i,b:j,internalAvg,betweenAvg})}}return{ready,total,submitted,relationCount:relationResponders.length,students,scores,mutual,groups,groupByStudent,connectors,peripheral,groupMetrics}}
function renderRelationships(){const content=$('#relationContent');const confidence=$('#relationConfidence');if(!content||!confidence)return;const analysis=buildRelationshipAnalysis(allResponses,selectedAnalysisMonth);const rate=analysis.total?Math.round(analysis.submitted/analysis.total*100):0;const relationRate=analysis.total?Math.round(analysis.relationCount/analysis.total*100):0;confidence.className=`confidence ${analysis.ready?'good':''}`;confidence.textContent=analysis.ready?`분석 가능 · 제출 ${rate}% · 관계 문항 ${relationRate}%`:`데이터 부족 · 제출 ${rate}% · 관계 문항 ${relationRate}%`;if(!analysis.ready){content.innerHTML='<div class="notice warning relation-warning"><span>!</span><div><strong>관계 구조를 해석하기에는 데이터가 부족합니다.</strong><p>개별 도움 요청은 확인할 수 있지만, 제출률과 관계 문항 작성률이 모두 80% 이상일 때 추정 집단과 관계망을 표시합니다.</p></div></div>';return}const width=900,height=480;const positions=new Map();const palette=['#d9edf4','#e8e0f4','#dff3e9','#fff0d8','#f7dfe3'];analysis.groups.forEach((group,index)=>{const centerX=150+(index%4)*210,centerY=130+Math.floor(index/4)*210;group.forEach((number,nodeIndex)=>{const angle=2*Math.PI*nodeIndex/group.length;positions.set(number,{x:centerX+Math.cos(angle)*70,y:centerY+Math.sin(angle)*70,group:index})})});const unplaced=analysis.students.filter(student=>!positions.has(Number(student.number)));unplaced.forEach((student,index)=>positions.set(Number(student.number),{x:100+(index%8)*100,y:height-55-Math.floor(index/8)*75,group:-1}));const lines=analysis.mutual.map(edge=>{const a=positions.get(edge.a),b=positions.get(edge.b);const cross=a.group!==b.group;return`<line class="${cross?'bridge':''}" x1="${a.x}" y1="${a.y}" x2="${b.x}" y2="${b.y}"/>`}).join('');const nodes=analysis.students.map((student,index)=>{const pos=positions.get(Number(student.number));const fill=pos.group>=0?palette[pos.group%palette.length]:'#eef1f3';return`<g transform="translate(${pos.x} ${pos.y})" data-student-node><circle r="25" style="fill:${fill}"/><text>${String.fromCharCode(65+index%26)}</text><title>${escapeHTML(student.name)}</title></g>`}).join('');const groupCards=analysis.groups.length?analysis.groups.map((group,index)=>`<article><strong>추정 집단 ${index+1} · ${group.length}명</strong><p>${group.map(number=>escapeHTML(classSettings.students.find(student=>Number(student.number)===number)?.name||`${number}번`)).join(', ')}</p></article>`).join(''):'<p class="muted">상호 5점 연결을 중심으로 구분되는 추정 집단이 없습니다.</p>';content.innerHTML=`<div class="relation-grid actual-relations"><div class="panel network-panel"><div class="panel-head"><div><p class="eyebrow">실제 월별 응답</p><h3>${monthLabel(selectedAnalysisMonth)} 관계망</h3></div><button class="text-button" id="toggleNames">이름 표시</button></div><div class="network" id="network" aria-label="학생 관계망 추정도"><svg viewBox="0 0 ${width} ${height}" role="img"><g class="links">${lines}</g><g class="nodes">${nodes}</g></svg></div><p class="muted">상호 4~5점 연결을 표시하고, 상호 5점 연결이 이어지는 묶음을 추정 집단으로 계산했습니다.</p></div><div class="relation-notes"><div class="panel"><span class="tag open">추정 집단 ${analysis.groups.length}개</span><h3>상호 높은 관계가 밀집된 묶음</h3><div class="group-list">${groupCards}</div><p class="muted">친한 무리나 고정 집단을 확정한 결과가 아닙니다.</p></div><div class="panel"><span class="tag blue-tag">집단 연결 역할 가능 ${analysis.connectors.length}명</span><h3>여러 집단과 연결된 학생</h3><p>${analysis.connectors.length?analysis.connectors.map(item=>`${escapeHTML(item.name)} (${item.groups.map(group=>`집단 ${group+1}`).join('·')})`).join('<br>'):'뚜렷한 후보 없음'}</p><p class="muted">관계 조정 부담이 있는지도 함께 관찰해 주세요.</p></div><div class="panel"><span class="tag watch">관계 연결 확인 ${analysis.peripheral.length}명</span><h3>강한 상호 연결이 적은 학생</h3><p>${analysis.peripheral.length?analysis.peripheral.map(item=>`${escapeHTML(item.name)} · 상호 연결 ${item.connections}명`).join('<br>'):'뚜렷한 후보 없음'}</p><p class="muted">실제 놀이·모둠 참여를 확인하기 위한 후보이며, 고립을 의미하지 않습니다.</p></div><div class="panel"><span class="tag orange-tag">집단 간 관계 차이 ${analysis.groupMetrics.length}건</span><h3>집단별 관계 경험 차이</h3><p>${analysis.groupMetrics.length?analysis.groupMetrics.map(item=>`집단 ${item.a+1}↔${item.b+1} · 내부 ${item.internalAvg.toFixed(1)} / 집단 간 ${item.betweenAvg.toFixed(1)}`).join('<br>'):'뚜렷한 차이 없음'}</p><p class="muted">모둠·체육·놀이 상황의 경쟁이나 배제 여부를 실제로 확인해 주세요.</p></div></div></div>`}
function renderAnalysisStatus(){const current=latestByStudent(allResponses,selectedAnalysisMonth);const total=classSettings.students.length;const submitted=current.size;const rate=total?Math.round(submitted/total*100):0;const monthlyRows=allResponses.filter(item=>monthOf(item)===selectedAnalysisMonth);const duplicateCount=Math.max(0,monthlyRows.length-submitted);const relationshipCount=[...current.values()].filter(item=>(payloadOf(item).relationships||[]).length).length;const relationshipRate=total?Math.round(relationshipCount/total*100):0;const relationshipReady=rate>=80&&relationshipCount>=Math.ceil(total*.8);const concernCounts={친구:0,공부:0,성적:0,등하교:0,가정:0};current.forEach(item=>{const text=String(payloadOf(item).studentState?.worryDetail||'');Object.keys(concernCounts).forEach(key=>{if(text.includes(key))concernCounts[key]++})});const concerns=Object.entries(concernCounts).filter(([,count])=>count).sort((a,b)=>b[1]-a[1]).map(([key,count])=>`${key} ${count}건`).join(' · ')||'분류된 공통 고민 없음';const el=$('#analysisDataStatus');el.className=`notice ${relationshipReady?'safe':'warning'}`;el.innerHTML=`<span>${relationshipReady?'✓':'!'}</span><div><strong>${monthLabel(selectedAnalysisMonth)} 데이터 상태 · 제출 ${submitted}/${total}명 (${rate}%) · 관계 문항 ${relationshipCount}/${total}명 (${relationshipRate}%)</strong><p>학생별 최신 제출을 분석합니다${duplicateCount?` · 추가 제출 ${duplicateCount}건은 최신 응답으로 대체됨`:''}. 관계 구조 분석: <b>${relationshipReady?'참고 가능':'데이터 부족'}</b>${relationshipReady?'':' (제출·관계 문항 응답률 80% 이상 필요)'} · 공통 고민: ${escapeHTML(concerns)}</p></div>`}
function loadClassSettings(){return JSON.parse(JSON.stringify(defaultSettings))}
function persistClassSettings(){localStorage.removeItem('ieum-class-settings');localStorage.removeItem('ieum-teacher-secret');localStorage.removeItem('ieum-observations')}
function syncSignalNames(){}
function renderClassIdentity(){const {teacherName,grade,classNumber}=classSettings;$('#profileAvatar').textContent=teacherName.trim().charAt(0)||'교';$('#profileTeacher').textContent=teacherName?`${teacherName} 선생님`:'담임교사';$('#profileClass').textContent=classSettings.classId?`${grade}학년 ${classNumber}반 담임`:'학급을 연결해 주세요'}
function renderSettings(){const {teacherName,schoolYear,grade,classNumber,classId,students}=classSettings;$('#teacherName').value=teacherName;$('#schoolYear').value=schoolYear;$('#grade').value=grade;$('#classNumber').value=classNumber;$('#classId').value=classId||'';$('#teacherSecret').value='';$('#rosterCount').textContent=`${students.length}명`;$('#rosterBody').innerHTML=students.map((student,index)=>`<tr><td><input type="number" min="1" max="99" value="${student.number}" data-student-number="${index}" aria-label="${index+1}번째 학생 번호"></td><td><input maxlength="20" value="${escapeHTML(student.name)}" data-student-name="${index}" aria-label="${index+1}번째 학생 이름"></td><td><button class="remove-student" type="button" data-remove-student="${index}" aria-label="${escapeHTML(student.name)} 삭제">삭제</button></td></tr>`).join('')}
function collectSettingsForm(){const students=$$('#rosterBody tr').map((row,index)=>({number:Number(row.querySelector('[data-student-number]').value),name:row.querySelector('[data-student-name]').value.trim(),studentId:classSettings.students[index]?.studentId||null,accessCode:classSettings.students[index]?.accessCode||''})).filter(student=>student.name).sort((a,b)=>a.number-b.number);return{teacherName:$('#teacherName').value.trim(),schoolYear:Number($('#schoolYear').value),grade:Number($('#grade').value),classNumber:Number($('#classNumber').value),classId:$('#classId').value.trim(),teacherSecret:$('#teacherSecret').value.trim(),students}}
async function applySettings(){const next=collectSettingsForm();if(!getTeacherSession()){showToast('교사 로그인이 필요합니다.');return false}if(!next.classId||!next.teacherName||!next.students.length){showToast('학급 ID, 교사 이름과 학생을 한 명 이상 입력해 주세요.');return false}try{await teacherRpc('teacher_update_class_context_auth',{p_class_id:next.classId,p_teacher_name:next.teacherName,p_school_year:next.schoolYear,p_grade:next.grade,p_class_number:next.classNumber});await teacherRpc('teacher_sync_roster_auth',{p_class_id:next.classId,p_students:next.students.map(({number,name,studentId})=>({number,name,studentId}))});classSettings={...next,teacherSecret:''};syncSignalNames();renderClassIdentity();renderSettings();renderStudents();renderParticipationLink();renderHomeSignals();renderClassTrend();renderAnalysis($('.filter-tabs .active')?.dataset.filter||'all');renderStudentDetailSelector();showToast('학급 정보와 명단을 DB에 저장했습니다.');return true}catch(error){showToast(`학급 설정 저장 실패: ${error.message}`);return false}}
function renderParticipationLink(){const code=document.querySelector('.copy-row code'),qr=$('#participationQr'),token=classSettings.participationToken;if(!token){if(code)code.textContent='DB 마이그레이션 후 참여 링크가 생성됩니다.';if(qr)qr.innerHTML='<p class="muted">참여 토큰 없음</p>';$('#copyLink').dataset.link='';return}const url=new URL('student.html',location.href);url.searchParams.set('join',token);if(code)code.textContent=url.href;$('#copyLink').dataset.link=url.href;if(qr){try{if(typeof qrcode!=='function')throw new Error('QR 라이브러리 로드 실패');const value=qrcode(0,'M');value.addData(url.href);value.make();qr.innerHTML=value.createImgTag(5,8,'학생 참여 QR 코드')}catch(error){qr.innerHTML='<p class="muted">QR을 만들지 못했습니다. 링크를 복사해 주세요.</p>'}}}
function renderResponses(responses){const month=selectedAnalysisMonth||new Date().toISOString().slice(0,7);const monthly=responses.filter(item=>monthOf(item)===month);const submittedNumbers=new Set(monthly.map(item=>Number(item.student_number||payloadOf(item).studentNumber)));const total=classSettings.students.length;const submitted=submittedNumbers.size;const rate=total?Math.round(submitted/total*100):0;$('#studentGrid').innerHTML=classSettings.students.map(student=>`<span class="student-chip ${submittedNumbers.has(Number(student.number))?'':'missing'}">${escapeHTML(student.name)}</span>`).join('');$('#surveyParticipation').textContent=`${submitted} / ${total}명 · ${monthLabel(month)}`;$('#surveyParticipationBar').style.width=`${rate}%`;$('#homeParticipation').innerHTML=`${submitted} <small>/ ${total}명</small>`;$('#homeParticipationBar').style.width=`${rate}%`;$('#homeParticipationText').textContent=`${monthLabel(month)} ${rate}% 참여 · 미제출 ${Math.max(0,total-submitted)}명`;$('#responseList').innerHTML=monthly.length?`<h4>${monthLabel(month)} 제출 원문</h4>`+monthly.map(item=>{const payload=payloadOf(item);const name=item.student_name||payload.studentName||classSettings.students.find(student=>student.number===payload.studentNumber)?.name||'학생';const help=payload.helpNow||'괜찮음';const worry=payload.studentState?.worryDetail||'작성 내용 없음';return`<details><summary><strong>${escapeHTML(name)}</strong><span class="tag ${/바로|즉시/.test(help)?'urgent':/이번 주/.test(help)?'week':'watch'}">${escapeHTML(help)}</span></summary><p>${escapeHTML(worry)}</p></details>`}).join(''):'<p class="muted">선택한 월에 저장된 응답이 없습니다.</p>';renderMonthlySurveyAccordion(responses)}
function renderMonthlySurveyAccordion(responses){const container=$('#monthlySurveyAccordion');if(!container)return;const months=[...new Set(responses.map(monthOf).filter(month=>/^\d{4}-\d{2}$/.test(month)))].sort().reverse();const total=classSettings.students.length;if(!months.length){container.innerHTML='<h4>월별 설문 현황</h4><p class="muted">저장된 월별 설문이 없습니다.</p>';return}container.innerHTML='<h4>월별 설문 현황</h4>'+months.map((month,index)=>{const rows=responses.filter(item=>monthOf(item)===month);const latest=latestByStudent(rows,month);const submitted=[...latest.keys()];const submittedSet=new Set(submitted);const rate=total?Math.round(submitted.length/total*100):0;const missing=classSettings.students.filter(student=>!submittedSet.has(Number(student.number)));const duplicateCount=Math.max(0,rows.length-submitted.length);const submittedNames=classSettings.students.filter(student=>submittedSet.has(Number(student.number))).map(student=>student.name);return`<details ${month===selectedAnalysisMonth||(!selectedAnalysisMonth&&index===0)?'open':''}><summary><strong>${monthLabel(month)}</strong><span class="tag ${rate>=80?'open':rate?'week':'watch'}">${submitted.length}/${total}명 · ${rate}%</span></summary><div class="evidence-box"><p><strong>제출 학생 ${submitted.length}명</strong></p><p>${submittedNames.length?submittedNames.map(escapeHTML).join(', '):'없음'}</p><p><strong>미제출 학생 ${missing.length}명</strong></p><p>${missing.length?missing.map(student=>escapeHTML(student.name)).join(', '):'없음'}</p><p class="muted">저장된 응답 ${rows.length}건${duplicateCount?` · 추가 제출 ${duplicateCount}건`:''}</p><button type="button" class="text-button" data-select-survey-month="${month}">이 월의 원문·분석 보기 →</button></div></details>`}).join('')}
function normalizeParticipationLabel(){const label=$('#surveyParticipation');if(label)label.textContent=label.textContent.split(' · ')[0];const responseList=$('#responseList');if(responseList)responseList.innerHTML=''}
function applyAnalysisMonth(){signals=analyzeResponses(allResponses,selectedAnalysisMonth);renderResponses(allResponses);normalizeParticipationLabel();renderResponseManagement();renderAnalysisStatus();renderHomeSignals();renderClassTrend();renderAnalysis($('.filter-tabs .active')?.dataset.filter||'all');renderRelationshipsV2();renderRelationshipActions();renderStudentDetailSelector();renderStudentDetail();ensureAiAnalysis()}
async function refreshResponses(showNotice=true){if(!getTeacherSession()){if(showNotice)$('#authDialog').showModal();return}try{allResponses=(await teacherRpc('teacher_get_responses_auth',{p_class_id:classSettings.classId})).map(row=>{const student=row.student_id&&classSettings.students.find(item=>item.studentId===row.student_id);return student?{...row,student_number:student.number,student_name:student.name}:row});await Promise.all([refreshObservations(),refreshGovernance()]);updateMonthSelector();applyAnalysisMonth();if(showNotice)showToast('로그인 계정의 응답과 관찰 기록을 불러왔습니다.')}catch(error){showToast(`자료를 불러오지 못했습니다: ${error.message}`)}}
async function syncRoster(){await applySettings()}
function showToast(message){const el=$('#toast');el.textContent=String(message).replaceAll('AI 관찰 보조','AI 분석');el.classList.add('show');setTimeout(()=>el.classList.remove('show'),2200)}
function renderHomeSignals(){const urgentStudents=new Set(signals.filter(signal=>signal.type==='urgent'&&signal.studentNumber).map(signal=>Number(signal.studentNumber)));const observationStudents=new Set(signals.filter(signal=>signal.type!=='urgent'&&signal.studentNumber).map(signal=>Number(signal.studentNumber)));const latest=latestByStudent(allResponses,selectedAnalysisMonth);const positive=[...latest.values()].filter(item=>{const peer=payloadOf(item).peerObservations||{};return peer.kind?.detail||peer.growth?.detail}).length;$('#homeUrgent').innerHTML=`${urgentStudents.size} <small>명</small>`;$('#homeWeek').innerHTML=`${observationStudents.size} <small>명</small>`;$('#homePositive').innerHTML=`${positive} <small>건</small>`}
function classMonthlyTrend(responses){const byMonth=new Map();responses.filter(item=>!item.analysis_excluded).forEach(item=>{const month=monthOf(item),number=Number(item.student_number||payloadOf(item).studentNumber);if(!/^\d{4}-\d{2}$/.test(month)||!number)return;if(!byMonth.has(month))byMonth.set(month,new Map());const current=byMonth.get(month).get(number),time=new Date(item.submitted_at||payloadOf(item).submittedAt||0);if(!current||time>current.time)byMonth.get(month).set(number,{item,time})});return[...byMonth.entries()].sort(([a],[b])=>a.localeCompare(b)).slice(-6).map(([month,students])=>{const scores=[];students.forEach(({item})=>Object.values(payloadOf(item).selfRatings||{}).forEach(value=>{const score=Number(value?.score??value);if(score>=1&&score<=5)scores.push(score)}));return{month,participants:students.size,rate:classSettings.students.length?Math.round(students.size/classSettings.students.length*100):0,average:scores.length?scores.reduce((sum,value)=>sum+value,0)/scores.length:null}})}
function renderClassTrend(){const chart=$('#classTrendChart'),confidence=$('#classTrendConfidence'),insight=$('#classTrendInsight');if(!chart||!confidence||!insight)return;const trend=classMonthlyTrend(allResponses);if(!trend.length){confidence.textContent='등록 자료 0건';chart.innerHTML='<p class="muted class-trend-empty">설문이 제출되면 월별 실제 평균이 표시됩니다.</p>';insight.innerHTML='<span>ⓘ</span><p><strong>아직 비교할 자료가 없습니다.</strong><br>미제출과 분석 제외 응답은 평균에 포함하지 않습니다.</p>';return}confidence.textContent=`최근 ${trend.length}개월 · ${trend.at(-1).rate}% 참여`;chart.innerHTML=`<div class="chart-line">${trend.map((row,index)=>`<span class="${index===trend.length-1?'current':''}" style="height:${row.average?Math.max(12,row.average/5*82):8}%"><b>${row.average?row.average.toFixed(1):'—'}</b><small>${row.participants}명</small></span>`).join('')}</div><div class="chart-labels">${trend.map(row=>`<span>${Number(row.month.slice(5))}월</span>`).join('')}</div>`;const latest=trend.at(-1),before=trend.at(-2);if(!before||latest.average===null||before.average===null){insight.innerHTML=`<span>ⓘ</span><p><strong>${monthLabel(latest.month)} 실제 응답 ${latest.participants}명</strong><br>다음 달 자료가 쌓이면 변화 폭을 비교합니다.</p>`;return}const delta=latest.average-before.average,direction=Math.abs(delta)<.05?'비슷합니다':delta>0?'높아졌습니다':'낮아졌습니다';insight.innerHTML=`<span>${Math.abs(delta)<.05?'→':delta>0?'↗':'↘'}</span><p><strong>학급 자기평가 평균이 지난달보다 ${Math.abs(delta).toFixed(1)}점 ${direction}</strong><br>${before.participants}명과 ${latest.participants}명의 실제 제출 자료를 비교했습니다. 참여 학생 구성이 다를 수 있어 관찰과 함께 해석하세요.</p>`}
function renderAnalysis(filter='all'){const allGroups=groupedSignals();const counts={all:allGroups.length,urgent:allGroups.filter(group=>group.type==='urgent').length,watch:allGroups.filter(group=>group.type==='watch').length};$$('.filter-tabs button').forEach(button=>{const labels={all:'전체',urgent:'즉시 확인',watch:'지속 관찰'};button.textContent=`${labels[button.dataset.filter]} ${counts[button.dataset.filter]}`});const visible=groupedSignals(filter);$('#analysisCards').innerHTML=visible.length?visible.map(group=>{const evidenceCount=group.items.reduce((sum,item)=>sum+item.evidence.length,0);return`<article class="analysis-card" data-type="${group.type}"><header><div><div class="analysis-card-tags"><span class="tag ${group.type}">${group.tag}</span><span class="change-badge">${escapeHTML(group.trend)}</span></div><h3>${escapeHTML(group.name)} · 통합 확인 카드</h3><div class="signal-summary">${group.items.map(item=>`<p><strong>▣ ${escapeHTML(item.title)}</strong><br>${escapeHTML(item.summary)}</p>`).join('')}</div>${group.protectiveFactors.length?`<div class="protective-factors"><strong>긍정적 보호요인</strong><p>${group.protectiveFactors.map(item=>`✓ ${escapeHTML(item)}`).join(' · ')}</p></div>`:''}</div></header><footer><span class="evidence-count">신호 ${group.items.length}개 · 근거 ${evidenceCount}개</span><button class="evidence-button" data-evidence-group="${group.ids.join(',')}">통합 근거와 관찰 제안</button></footer></article>`}).join(''):'<div class="panel"><p class="muted">선택한 조건에 해당하는 실제 응답 신호가 없습니다.</p></div>'}
function aiTeacherDisplayText(value){return String(value||'').replace(/학생-(\d+)/g,(match,number)=>classSettings.students.find(student=>Number(student.number)===Number(number))?.name||match)}
function aiEvidenceHTML(value,display){const text=String(value||''),match=text.match(/^\[(계산 결과|학생 원문|친구 관찰)\]\s*(.*)$/);return match?`<span class="ai-evidence-row"><b>${escapeHTML(match[1])}</b>${display(match[2])}</span>`:`<span class="ai-evidence-row"><b>기존 근거</b>${display(text)}</span>`}
function renderAiAnalysis(result){const content=$('#aiAnalysisContent'),analysis=result.analysis||{},meta=result.meta||{},display=value=>escapeHTML(aiTeacherDisplayText(value));currentAiAnalysis=result;currentAiRun={id:meta.runId||result.id||null,status:meta.reviewStatus||'active'};$('#aiAnalysisMeta').textContent=`${monthLabel(meta.month||selectedAnalysisMonth)} · ${meta.responseCount||0}명 · ${meta.cached?'저장 결과':'새 분석'} · ${meta.model||'AI'} · ${meta.analysisVersion||'버전 확인 불가'}`;const priority=(analysis.priority_students||[]).slice(0,3),patterns=analysis.class_patterns||[],judgment=analysis.overall_judgment||analysis.summary||'종합 판단이 없습니다.';content.innerHTML=`<section class="ai-overall-judgment"><p class="eyebrow">종합 판단</p><p class="ai-summary">${display(judgment)}</p></section><div class="ai-priority-heading"><h4>주의 깊게 볼 학생 ${priority.length}명</h4><span>순위가 아닌 지원 확인 대상 · 최대 3명</span></div><div class="ai-priority-grid">${priority.length?priority.map(item=>`<article class="ai-result-card"><div class="ai-student-rank"><div><span class="tag ${item.priority==='즉시 확인'?'urgent':'watch'}">${display(item.priority)}</span><h4>${display(item.student)}</h4></div></div><div class="ai-evidence-list"><strong>유형별 근거</strong>${(item.evidence||[]).map(value=>aiEvidenceHTML(value,display)).join('')}</div><p><strong>가능한 해석</strong><br>${(item.possible_interpretations||[]).map(value=>`• ${display(value)}`).join('<br>')}</p><p class="coaching-direction"><strong>담임 관찰 포인트·코칭 방향</strong><br>${display(item.coaching_direction||(item.teacher_checks||[]).join(' · '))}</p><p><strong>확인할 장면·질문</strong><br>${(item.teacher_checks||[]).map(value=>`✓ ${display(value)}`).join('<br>')}</p></article>`).join(''):'<div class="ai-no-priority"><strong>추가 확인 학생 없음</strong><p>현재 입력에서 의미 있는 복수 신호가 충분하지 않습니다. 일반적인 학급 관찰은 계속해 주세요.</p></div>'}</div>${patterns.length?`<details class="ai-limitations"><summary>학급 단위 관찰 패턴 보기</summary>${patterns.map(item=>`<article class="ai-result-card"><h4>${display(item.pattern)}</h4><div class="ai-evidence-list">${(item.evidence||[]).map(value=>aiEvidenceHTML(value,display)).join('')}</div><p><strong>확인 제안</strong><br>${display(item.teacher_check)}</p></article>`).join('')}</details>`:''}<details class="ai-limitations"><summary>분석 한계 보기</summary><p>${(analysis.limitations||[]).map(value=>`• ${display(value)}`).join('<br>')||'AI 결과는 실제 관찰을 대신하지 않습니다.'}</p></details>`}
async function runAiAnalysis(force=false){const button=force?$('#rerunAiAnalysis'):$('#runAiAnalysis');if(!getTeacherSession()){showToast('교사 로그인이 필요합니다.');$('#authDialog').showModal();return}if(force&&!confirm('저장 결과를 사용하지 않고 AI를 새로 호출할까요? 월별 호출 한도에 포함됩니다.'))return;button.disabled=true;const label=button.textContent;button.textContent='안전하게 분석 중…';try{const result=await teacherEdgeFunction('analyze-class',{classId:classSettings.classId,month:selectedAnalysisMonth,force});renderAiAnalysis(result);showToast(result.meta?.cached?'저장된 AI 분석을 불러왔습니다.':'새 AI 분석을 저장했습니다.')}catch(error){showToast(`AI 분석 실패: ${error.message}`)}finally{button.disabled=false;button.textContent=label}}
async function ensureAiAnalysis(){const key=`${classSettings.classId}:${selectedAnalysisMonth}`;if(!getTeacherSession()||!classSettings.classId||!allResponses.some(item=>monthOf(item)===selectedAnalysisMonth)||aiAutoKey===key)return;aiAutoKey=key;$('#aiAnalysisMeta').textContent='자동 분석 중…';$('#aiAnalysisContent').innerHTML='<p class="muted">저장된 결과를 확인하고 있습니다.</p>';try{const result=await teacherEdgeFunction('analyze-class',{classId:classSettings.classId,month:selectedAnalysisMonth,force:false});renderAiAnalysis(result)}catch(error){aiAutoKey='';$('#aiAnalysisMeta').textContent='분석을 불러오지 못함';$('#aiAnalysisContent').innerHTML=`<p class="muted">${escapeHTML(error.message)} · 위의 AI 분석 버튼으로 다시 시도해 주세요.</p>`}}
async function reviewAiAnalysis(status){if(!currentAiRun?.id){showToast('저장된 AI 분석 ID가 없습니다.');return}const note=prompt(status==='flagged'?'오류라고 판단한 이유를 입력해 주세요.':'숨기는 이유를 입력해 주세요.');if(!note?.trim())return;try{await teacherRpc('teacher_review_ai_analysis_auth',{p_class_id:classSettings.classId,p_run_id:currentAiRun.id,p_status:status,p_note:note.trim()});if(status==='hidden')$('#aiAnalysisPanel').hidden=true;else $('#aiAnalysisMeta').textContent+=' · 교사 오류 표시';showToast('AI 결과 검토 상태와 감사 로그를 저장했습니다.')}catch(error){showToast(`AI 검토 저장 실패: ${error.message}`)}}
function renderStudents(){renderResponses([])}
function studentMonthlyResponses(studentNumber){const months=[...new Set(allResponses.map(monthOf).filter(month=>/^\d{4}-\d{2}$/.test(month)))].sort();return months.map(month=>({month,item:latestByStudent(allResponses,month).get(Number(studentNumber))})).filter(row=>row.item)}
function renderStudentDetailSelector(){const select=$('#studentDetailSelect');if(!select)return;const previous=Number(select.value),selected=classSettings.students.some(student=>Number(student.number)===previous)?previous:0;select.innerHTML='<option value="">학생을 선택해 주세요</option>'+classSettings.students.map(student=>`<option value="${Number(student.number)}" ${Number(student.number)===selected?'selected':''}>${Number(student.number)}번 ${escapeHTML(student.name)}</option>`).join('')}
function receivedPositiveMentions(student,month){const mentions=[];latestByStudent(allResponses,month).forEach((item,reporter)=>{if(reporter===Number(student.number))return;const peer=payloadOf(item).peerObservations||{};[['친절·존중',peer.kind?.detail],['성장',peer.growth?.detail]].forEach(([type,detail])=>{const text=String(detail||'').trim();if(text.includes(student.name))mentions.push({type,text,reporter:item.student_name||payloadOf(item).studentName||`${reporter}번`})})});return mentions}
function incomingRelationshipFor(studentNumber,month){const values=[];latestByStudent(allResponses,month).forEach((item,rater)=>{if(rater===Number(studentNumber))return;const row=(payloadOf(item).relationships||[]).find(entry=>Number(entry.targetNumber)===Number(studentNumber));if(row&&Number(row.score)>0)values.push(Number(row.score))});return values.length?{average:values.reduce((sum,value)=>sum+value,0)/values.length,count:values.length}:null}
function studentResponseInsights(student,monthly){const latestRow=monthly.at(-1),payload=payloadOf(latestRow.item),month=latestRow.month,outgoing=(payload.relationships||[]).map(item=>Number(item.score)).filter(score=>score>=1&&score<=5),incoming=incomingRelationshipFor(student.number,month),selfScores=Object.values(payload.selfRatings||{}).map(value=>Number(value?.score)).filter(score=>score>=1&&score<=5),selfAverage=selfScores.length?selfScores.reduce((sum,value)=>sum+value,0)/selfScores.length:null,worry=String(payload.studentState?.worryDetail||'').trim(),help=String(payload.helpNow||'').trim(),items=[];if(outgoing.length>=4){const average=outgoing.reduce((sum,value)=>sum+value,0)/outgoing.length,sd=Math.sqrt(outgoing.reduce((sum,value)=>sum+(value-average)**2,0)/outgoing.length),unique=new Set(outgoing).size;if(unique===1||sd<.35)items.push({tone:'data',title:'관계 응답의 변별력이 낮을 수 있어요',body:`친구 ${outgoing.length}명에게 준 점수가 ${unique===1?'모두 같음':`거의 비슷함(표준편차 ${sd.toFixed(2)})`} · 관계를 실제로 동일하게 느꼈을 수도 있으므로 답변 태도나 문항 이해를 가볍게 확인하세요.`})}const noStatedWorry=!worry||/^(없|없음|없어요|괜찮|괜찮아요|잘 모르겠어요)[.! ]*$/.test(worry),noHelpRequest=!help||/없|괜찮|도움 필요 없음/.test(help),saysOkay=noStatedWorry&&noHelpRequest,outsideConcern=incoming&&incoming.count>=4&&incoming.average<=2.8;if(saysOkay&&outsideConcern&&(selfAverage===null||selfAverage>=3.5))items.push({tone:'watch',title:'어려움을 드러내지 않았을 가능성을 확인해 주세요',body:`본인은 뚜렷한 고민이나 도움 요청을 적지 않았지만 친구들에게 받은 관계 점수는 ${incoming.average.toFixed(1)}점(${incoming.count}명)입니다. 어려움을 숨긴다고 단정하지 말고 쉬는 시간·모둠 활동 관찰 후 비공개로 편안하게 물어보세요.`});if(!items.length)items.push({tone:'safe',title:'응답에서 뚜렷한 추가 확인 신호가 보이지 않아요',body:'이 표시는 설문 응답 범위 안의 간단한 점검입니다. 실제 행동 관찰과 학생 대화를 함께 확인하세요.'});return{month,items}}
function renderStudentResponseInsights(student,monthly){const target=$('#studentResponseInsight');if(!target)return;if(!student||!monthly?.length){target.innerHTML='';return}const insight=studentResponseInsights(student,monthly);target.innerHTML=`<section class="panel student-response-insight"><div class="panel-head"><div><p class="eyebrow">${monthLabel(insight.month)} 응답 점검</p><h3>학생별 간단한 분석</h3></div><span class="confidence">진단이 아닌 확인 단서</span></div><div class="student-insight-grid">${insight.items.map(item=>`<article class="student-insight-card ${item.tone}"><h4>${escapeHTML(item.title)}</h4><p>${escapeHTML(item.body)}</p></article>`).join('')}</div></section>`}
function renderStudentDetail(){
  const content=$('#studentDetailContent'),select=$('#studentDetailSelect'),insight=$('#studentResponseInsight');if(!content||!select)return;
  if(!select.value){if(insight)insight.innerHTML='';content.innerHTML='<div class="panel student-empty"><strong>학생을 선택해 주세요.</strong><p class="muted">선택한 학생의 월별 추세와 설문 내용을 표시합니다.</p></div>';return}const student=classSettings.students.find(row=>Number(row.number)===Number(select.value));if(!student){if(insight)insight.innerHTML='';content.innerHTML='<div class="panel"><p class="muted">학급 설정에서 학생을 등록해 주세요.</p></div>';return}
  const monthly=studentMonthlyResponses(student.number),observations=getObservations().filter(item=>Number(item.studentNumber)===Number(student.number)||(!item.studentNumber&&item.student===student.name));
  renderStudentResponseInsights(student,monthly);if(!monthly.length){content.innerHTML=`<div class="panel student-empty"><h3>${escapeHTML(student.name)} 학생</h3><p class="muted">분석에 포함된 설문 응답이 아직 없습니다. 관찰 기록 ${observations.length}건은 관찰 기록 화면에서 확인할 수 있습니다.</p></div>`;return}
  const ratingLabels={study:'학습',listening:'경청',respect:'관계 존중',manners:'예의',responsibility:'책임감'},latest=payloadOf(monthly.at(-1).item),latestMonth=monthly.at(-1).month;
  const trendRows=Object.entries(ratingLabels).map(([key,label])=>`<div class="student-trend-row"><strong>${label}</strong>${monthly.map(({month,item})=>{const score=Number(payloadOf(item).selfRatings?.[key]?.score)||0;return`<span title="${monthLabel(month)} ${score||'미응답'}점"><i style="--score:${score}"></i><b>${score||'-'}</b></span>`}).join('')}</div>`).join(''),monthHeads=monthly.map(({month})=>`<span>${Number(month.slice(5))}월</span>`).join('');
  const positiveTotal=monthly.reduce((sum,row)=>sum+receivedPositiveMentions(student,row.month).length,0),relationLatest=incomingRelationshipFor(student.number,latestMonth);
  const timeline=monthly.slice().reverse().map(({month,item})=>{const payload=payloadOf(item),ratings=payload.selfRatings||{},mentions=receivedPositiveMentions(student,month),incoming=incomingRelationshipFor(student.number,month),state=payload.studentState||{};return`<article class="student-month-card"><header><div><p class="eyebrow">${monthLabel(month)}</p><h3>${escapeHTML(student.name)} 학생의 응답</h3></div><span class="tag ${/바로|즉시/.test(payload.helpNow||'')?'urgent':/이번 주/.test(payload.helpNow||'')?'week':'open'}">${escapeHTML(payload.helpNow||'도움 요청 없음')}</span></header><div class="monthly-score-list">${Object.entries(ratingLabels).map(([key,label])=>`<span>${label} <b>${Number(ratings[key]?.score)||'-'}</b></span>`).join('')}</div><div class="student-detail-grid"><section><h4>학생이 남긴 내용</h4><p><strong>학교생활 고민</strong><br>${escapeHTML(state.worryDetail||'작성 내용 없음')}</p><p><strong>선생님께 듣고 싶은 말</strong><br>${escapeHTML(state.teacherWish||'작성 내용 없음')}</p><p><strong>해결되지 않은 관계</strong><br>${escapeHTML(payload.unresolved?.detail||'작성 내용 없음')}</p></section><section><h4>관계·긍정 단서</h4><p><strong>받은 관계 점수</strong><br>${incoming?`응답 ${incoming.count}명 평균 ${incoming.average.toFixed(1)}점`:'해당 월 응답 없음'}</p><p><strong>친구의 긍정 언급 ${mentions.length}건</strong></p>${mentions.length?mentions.map(mention=>`<blockquote><b>${escapeHTML(mention.type)}</b> · ${escapeHTML(mention.reporter)}<br>${escapeHTML(mention.text)}</blockquote>`).join(''):'<p class="muted">이름이 포함된 친절·성장 서술이 없습니다.</p>'}</section></div></article>`}).join('');
  content.innerHTML=`<div class="student-summary-grid"><article class="stat-card"><span>제출 월</span><strong>${monthly.length}<small>개월</small></strong><p>${monthLabel(monthly[0].month)} ~ ${monthLabel(latestMonth)}</p></article><article class="stat-card"><span>최근 교우관계 표정</span><strong>${latest.selfSmile?'😊':'—'}</strong><p>${monthLabel(latestMonth)} 응답</p></article><article class="stat-card"><span>친구의 긍정 언급</span><strong>${positiveTotal}<small>건</small></strong><p>전체 제출 월 누적</p></article><article class="stat-card"><span>연결된 관찰 기록</span><strong>${observations.length}<small>건</small></strong><p>${relationLatest?`최근 받은 관계 평균 ${relationLatest.average.toFixed(1)}점`:'최근 관계 응답 없음'}</p></article></div><section class="panel student-trend-panel"><div class="panel-head"><div><p class="eyebrow">자기평가 변화</p><h3>월별 1~5점 추세</h3></div><span class="confidence">미제출·분석 제외는 계산하지 않음</span></div><div class="student-trend-scroll"><div class="student-trend-head"><strong>영역</strong>${monthHeads}</div>${trendRows}</div></section><section class="student-timeline"><div class="panel-head"><div><p class="eyebrow">월별 근거</p><h3>응답과 관계 단서</h3></div></div>${timeline}</section>`
}
