function openObservationForm(item={}){const dialog=$('#observationDialog');$('#observationDialogTitle').textContent=item.id?'관찰 확인 수정':'관찰 확인 추가';$('#observationId').value=item.id||'';$('#observationAiRunId').value=item.aiRunId||'';$('#observationSourceType').value=item.sourceType||'manual';$('#observationSourceSnapshot').value=JSON.stringify(item.sourceSnapshot||{});$('#observationStudent').innerHTML='<option value="">학급 전체</option>'+classSettings.students.map(student=>`<option value="${student.number}">${student.number}번 ${escapeHTML(student.name)}</option>`).join('');$('#observationStudent').value=item.studentNumber||'';$('#observationStatus').value=item.status||'todo';$('#observationOutcome').value=item.outcome||'pending';$('#observationTitle').value=item.title||'';$('#observationPlan').value=item.detail||'';$('#observationFact').value=item.observedFact||'';$('#observationInterpretation').value=item.teacherInterpretation||'';$('#observationInterview').value=item.interviewNote||'';$('#observationFollowUpDate').value=item.followUpDate||'';$('#observationFollowUp').value=item.followUp||'';dialog.querySelector('.observation-advanced').open=Boolean(item.detail||item.teacherInterpretation||item.followUpDate||item.followUp);dialog.showModal()}
function openEvidence(id){const s=signals.find(x=>x.id===Number(id));if(!s)return;$('#dialogTitle').textContent=`${s.name} · ${s.title}`;$('#dialogContent').innerHTML=`<h3>연결된 근거</h3>${s.evidence.map(e=>`<div class="evidence-box">${escapeHTML(e)}</div>`).join('')}<h3>가능한 해석</h3><div class="hypotheses">${s.hypotheses.map(h=>`<span>${escapeHTML(h)}</span>`).join('')}</div><h3>추천 관찰</h3><p>${escapeHTML(s.observation)}</p><div class="notice warning"><span>!</span><p>가능성에 대한 가설입니다. 원문 검토와 실제 관찰·대화로 확인해 주세요.</p></div>`;$('#saveObservation').dataset.signal=id;delete $('#saveObservation').dataset.signalGroup;$('#evidenceDialog').showModal()}
function openEvidenceGroup(ids){const items=String(ids).split(',').map(Number).map(id=>signals.find(signal=>signal.id===id)).filter(Boolean);if(!items.length)return;const name=items[0].name;$('#dialogTitle').textContent=`${name} · 통합 근거`;$('#dialogContent').innerHTML=items.map(item=>`<section><span class="tag ${item.type}">${item.tag}</span><h3>▣ 계산·분류 결과</h3><p><strong>${escapeHTML(item.title)}</strong><br>${escapeHTML(item.summary)}</p><h3>“ ” 연결된 학생 응답·계산 근거</h3>${item.evidence.map(e=>`<div class="evidence-box">${escapeHTML(e)}</div>`).join('')}<h3>? 가능한 해석</h3><div class="hypotheses">${item.hypotheses.map(h=>`<span>${escapeHTML(h)}</span>`).join('')}</div><h3>✓ 교사 확인 제안</h3><p>${escapeHTML(item.observation)}</p></section>`).join('<hr>')+`<div class="notice warning"><span>!</span><p>계산 결과와 가능성에 대한 가설입니다. 원문 검토와 실제 관찰·대화로 확인해 주세요.</p></div>`;$('#saveObservation').dataset.signal=items[0].id;$('#saveObservation').dataset.signalGroup=items.map(item=>item.id).join(',');$('#evidenceDialog').showModal()}
