function buildAiReportSection(scope,selectedNumber,includeNames){const analysis=currentAiAnalysis?.analysis||{},show=value=>escapeHTML(includeNames?aiTeacherDisplayText(value):value),allPriority=(analysis.priority_students||[]).slice(0,3),priority=scope==='student'?allPriority.filter(item=>item.student===`학생-${selectedNumber}`):allPriority,patterns=scope==='class'?(analysis.class_patterns||[]):[],judgment=analysis.overall_judgment||analysis.summary||'AI 종합 판단이 없습니다.';return`<section class="pdf-ai-section"><h2>AI 분석</h2><h3>종합 판단</h3><p>${show(judgment)}</p><h3>주의 깊게 볼 학생 ${priority.length}명</h3>${priority.length?priority.map(item=>`<article><h4>${show(item.student)} · ${show(item.priority)}</h4><p><b>학생별 받은 평가 근거</b><br>${(item.evidence||[]).map(value=>`• ${show(value)}`).join('<br>')}</p><p><b>가능한 해석</b><br>${(item.possible_interpretations||[]).map(value=>`• ${show(value)}`).join('<br>')}</p><p><b>담임 관찰 포인트·코칭 방향</b><br>${show(item.coaching_direction||(item.teacher_checks||[]).join(' · '))}</p><p><b>확인할 장면·질문</b><br>${(item.teacher_checks||[]).map(value=>`✓ ${show(value)}`).join('<br>')}</p></article>`).join(''):'<p>이 범위에서 우선 확인 대상으로 제시된 학생이 없습니다.</p>'}${patterns.length?`<h3>학급 단위 관찰 패턴</h3>${patterns.map(item=>`<article><h4>${show(item.pattern)}</h4><p>${(item.evidence||[]).map(value=>`• ${show(value)}`).join('<br>')}</p><p><b>확인 제안</b><br>${show(item.teacher_check)}</p></article>`).join('')}`:''}<h3>분석 한계</h3><p>${(analysis.limitations||[]).map(value=>`• ${show(value)}`).join('<br>')||'AI 결과는 실제 관찰을 대신하지 않습니다.'}</p></section>`}
async function downloadPdfDocument(content,fileName){if(typeof html2canvas!=='function'||!window.jspdf?.jsPDF)throw new Error('PDF 구성 요소를 불러오지 못했습니다. 새로고침 후 다시 시도해 주세요.');const root=document.createElement('section');root.className='pdf-render-root';root.innerHTML=content;document.body.append(root);try{if(document.fonts?.ready)await document.fonts.ready;const canvas=await html2canvas(root,{scale:2,backgroundColor:'#ffffff',logging:false,useCORS:true});const{jsPDF}=window.jspdf,pdf=new jsPDF({orientation:'portrait',unit:'mm',format:'a4',compress:true}),pageWidth=210,pageHeight=297,imageHeight=canvas.height*pageWidth/canvas.width,image=canvas.toDataURL('image/jpeg',0.94);let remaining=imageHeight,position=0;pdf.addImage(image,'JPEG',0,position,pageWidth,imageHeight,undefined,'FAST');remaining-=pageHeight;while(remaining>0){position=remaining-imageHeight;pdf.addPage();pdf.addImage(image,'JPEG',0,position,pageWidth,imageHeight,undefined,'FAST');remaining-=pageHeight}pdf.save(`${fileName.replace(/[\\/:*?"<>|]/g,'-')}.pdf`)}finally{root.remove()}}
$('#reportForm').addEventListener('submit',async event=>{event.preventDefault();const submit=event.submitter;submit.disabled=true;const oldLabel=submit.textContent;submit.textContent='PDF 만드는 중…';try{const scope=$('#reportScope').value,includeNames=$('#reportIncludeNames').checked,includeOriginals=$('#reportIncludeOriginals').checked,selectedNumber=Number($('#reportStudent').value);if(currentAiAnalysis?.meta?.month!==selectedAnalysisMonth){aiAutoKey='';await ensureAiAnalysis()}if(!currentAiAnalysis||currentAiAnalysis?.meta?.month!==selectedAnalysisMonth)throw new Error('현재 월의 AI 분석 결과를 먼저 불러와 주세요.');const rows=scope==='student'?allResponses.filter(item=>Number(item.student_number)===selectedNumber):allResponses,student=classSettings.students.find(item=>Number(item.number)===selectedNumber),trend=classMonthlyTrend(rows),title=scope==='student'?`${includeNames?student?.name||'학생':'선택 학생'} 보고서`:`${classSettings.grade}학년 ${classSettings.classNumber}반 학급 보고서`,summary=trend.map(row=>`<tr><td>${escapeHTML(monthLabel(row.month))}</td><td>${row.participants}명</td><td>${row.rate}%</td><td>${row.average?.toFixed(1)||'—'}</td></tr>`).join(''),originals=includeOriginals?rows.filter(item=>!item.analysis_excluded).map(item=>{const payload=payloadOf(item),name=includeNames?item.student_name:`학생-${item.student_number}`;return`<article><h3>${escapeHTML(name)} · ${escapeHTML(monthLabel(monthOf(item)))}</h3><p><b>학교생활 고민</b><br>${escapeHTML(payload.studentState?.worryDetail||'작성 내용 없음')}</p><p><b>도움 요청</b> ${escapeHTML(payload.helpNow||'없음')}</p></article>`}).join(''):'';const content=`<header><h1>${escapeHTML(title)}</h1><p>${escapeHTML(monthLabel(selectedAnalysisMonth))} 기준 · ${new Date().toLocaleDateString('ko-KR')}</p></header><p class="pdf-warning">이 보고서는 학생 지원을 위한 참고 자료이며 진단이나 사실 판정이 아닙니다.</p>${buildAiReportSection(scope,selectedNumber,includeNames)}<h2>월별 실제 응답 추세</h2><table><thead><tr><th>월</th><th>참여</th><th>참여율</th><th>자기평가 평균</th></tr></thead><tbody>${summary||'<tr><td colspan="4">자료 없음</td></tr>'}</tbody></table>${includeOriginals?`<h2>선택된 설문 원문</h2>${originals}`:''}`;await downloadPdfDocument(content,`${title}-${selectedAnalysisMonth}`);$('#reportDialog').close();showToast('AI 관찰 보조가 포함된 PDF를 다운로드했습니다.')}catch(error){showToast(`PDF 저장 실패: ${error.message}`)}finally{submit.disabled=false;submit.textContent=oldLabel}});
