  analysis.groups.forEach((group,index)=>{const centerAngle=groupCount===2?(index===0?Math.PI:0):-Math.PI/2+2*Math.PI*index/groupCount,gx=centerX+Math.cos(centerAngle)*centerRadius,gy=centerY+Math.sin(centerAngle)*centerRadius*.72,nodeRadius=Math.min(112,Math.max(68,48+group.length*8));group.forEach((number,nodeIndex)=>{const angle=-Math.PI/2+2*Math.PI*nodeIndex/group.length;positions.set(number,{x:gx+Math.cos(angle)*nodeRadius,y:gy+Math.sin(angle)*nodeRadius,group:index})})});
