  const nodes=analysis.students.map(student=>{const number=Number(student.number),pos=positions.get(number),fill=pos.group>=0?palette[pos.group%palette.length]:'#eef1f3';return`<g transform="translate(${pos.x.toFixed(1)} ${pos.y.toFixed(1)})" data-student-node data-number="${number}"><rect x="-54" y="-22" width="108" height="44" rx="14" style="fill:${fill}"/><text>${escapeHTML(student.name)}</text><title>${escapeHTML(student.name)}</title></g>`}).join('');
